              <Col key={i} md={6} lg={4} className="mb-4">
                <div className="retro-card">
                  <div className="retro-card-header" />
                  <Card.Body className="p-4">
                    <SkeletonText lines={2} />
                  </Card.Body>
                </div>
              </Col>
            ))}
          </Row>
        </Container>
      </div>
    );
